import React, { useEffect, useState } from 'react';
import './Navbar.css';

const NAV_ITEMS = [
  { href: '#home', label: 'Home' },
  { href: '#projects', label: 'Projects' },
  { href: '#experience', label: 'Experience' },
  { href: '#contact', label: 'Contact' },
];

export default function Navbar({ activeSection }) {
  const [isCompact, setIsCompact] = useState(false);
  const [menuOpen, setMenuOpen] = useState(false);

  useEffect(() => {
    const onScroll = () => setIsCompact(window.scrollY > 60);
    onScroll();
    window.addEventListener('scroll', onScroll);
    return () => window.removeEventListener('scroll', onScroll);
  }, []);

  const onNavigate = (href) => (event) => {
    event.preventDefault();
    const target = document.querySelector(href);
    if (!target) return;
    target.scrollIntoView({ behavior: 'smooth', block: 'start' });
    setMenuOpen(false);
  };

  return (
    <header className={`navbar ${isCompact ? 'compact' : ''}`}>
      <div className="navbar-inner">
        <a href="#home" onClick={onNavigate('#home')} className="brand">
          <span className="logo-mark">AC</span>
          <span className="brand-name">Abhi Chakrapani</span>
        </a>

        <button
          className={`hamburger ${menuOpen ? 'open' : ''}`}
          aria-label="Toggle menu"
          onClick={() => setMenuOpen((prev) => !prev)}
          type="button"
        >
          <span />
          <span />
          <span />
        </button>

        <nav className={`nav-links ${menuOpen ? 'open' : ''}`}>
          {NAV_ITEMS.map((item) => (
            <a
              key={item.href}
              href={item.href}
              onClick={onNavigate(item.href)}
              className={activeSection === item.href.slice(1) ? 'active' : ''}
            >
              {item.label}
            </a>
          ))}
        </nav>
      </div>
    </header>
  );
}
